- **CLI Commands**:
  - `nest generate module <module-name>`
  - `nest generate controller <controller-name>`
  - `nest generate service <service-name>`

- **Latest Versions**:
  - NestJS: v10.x
  - Mongoose: v7.x

- **Key Config Options**:
  - In the `app.module.ts`, use `MongooseModule.forRoot()` to configure MongoDB connection.
    ```typescript
    import { Module } from '@nestjs/common';
    import { MongooseModule } from '@nestjs/mongoose';

    @Module({
      imports: [
        MongooseModule.forRoot('mongodb://localhost/nestjs'),
      ],
    })
    export class AppModule {}
    ```
  - Define schemas with indexes in the model.
    ```typescript
    import { Schema, Document } from 'mongoose';

    export const UserSchema = new Schema({
      name: String,
      email: {
        type: String,
        index: true,
      },
    });

    export interface User extends Document {}
    ```
  - Use `@Prop({ index: true })` decorator for indexes in DTOs.
    ```typescript
    import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';

    @Schema()
    export class User {
      @Prop({ required: true })
      name: string;

      @Prop({ required: true, unique: true, index: true })
      email: string;
    }

    export const UserSchema = SchemaFactory.createForClass(User);
    ```

- **CLI Commands**:
  - `nest generate module database`
  - `nest generate service database`

- **Latest Versions**:
  - NestJS: v10.x
  - Mongoose: v7.x

- **Key Config Options**:
  - Database URI (`uri`)
  - Connection options (`useNewUrlParser`, `useUnifiedTopology`, etc.)
  - Transaction isolation level (`sessionOptions`)

Example of a basic `DatabaseModule` configuration:

```typescript
import { Module } from '@nestjs/common';
import { MongooseModule } from '@nestjs/mongoose';

@Module({
  imports: [
    MongooseModule.forRoot('mongodb://localhost:27017/mydatabase', {
      useNewUrlParser: true,
      useUnifiedTopology: true,
    }),
  ],
})
export class DatabaseModule {}
```

Example of using transactions with `@Transaction` decorator:

```typescript
import { Injectable } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Transaction, Transactional } from 'nestjs-mongo-transactions';

@Injectable()
export class TransactionsService {
  constructor(
    @InjectModel('Transaction') private readonly transactionModel: Model<any>,
  ) {}

  @Transactional()
  async createTransaction(@Transaction() session) {
    const newTransaction = new this.transactionModel({ /* data */ });
    await newTransaction.save({ session });
    // Additional operations
  }
}
```

